import type { Metadata } from "next";
import TransferFlow from "./TransferFlow";

export const metadata: Metadata = {
  title: "振込 | ぐんじょう銀行",
  description: "振込元口座の選択から本人確認までの振込手続き",
};

export default function TransferPage() {
  return <TransferFlow />;
}

// Domain data + format helpers for the 振込 (transfer) flow.
// Hand-rolled money/mask helpers are recorded as findings (no DS currency/masked
// primitive exists in @gunjo/ui@0.0.1-alpha.2).

export type AccountKind = "普通" | "当座";

export interface SourceAccount {
  id: string;
  bankName: string;
  branchName: string;
  kind: AccountKind;
  /** Full account number (never rendered unmasked). */
  number: string;
  /** Balance in yen, integer. */
  balance: number;
}

export interface Payee {
  id: string;
  label: string;
  bankName: string;
  branchName: string;
  kind: AccountKind;
  number: string;
  /** 口座名義 — katakana. */
  holder: string;
}

export const SOURCE_ACCOUNTS: SourceAccount[] = [
  {
    id: "acc-1",
    bankName: "ぐんじょう銀行",
    branchName: "本店営業部",
    kind: "普通",
    number: "1234567",
    balance: 1_284_530,
  },
  {
    id: "acc-2",
    bankName: "ぐんじょう銀行",
    branchName: "渋谷支店",
    kind: "普通",
    number: "7654321",
    balance: 38_900,
  },
  {
    id: "acc-3",
    bankName: "ぐんじょう銀行",
    branchName: "丸の内支店",
    kind: "当座",
    number: "0099887",
    balance: 5_402_110,
  },
];

export const SAVED_PAYEES: Payee[] = [
  {
    id: "payee-1",
    label: "ヤマダ タロウ（家賃）",
    bankName: "みどり銀行",
    branchName: "新宿支店",
    kind: "普通",
    number: "2345678",
    holder: "ヤマダ タロウ",
  },
  {
    id: "payee-2",
    label: "カブシキガイシャ アカネ",
    bankName: "さくら信用金庫",
    branchName: "横浜支店",
    kind: "当座",
    number: "0011223",
    holder: "カ）アカネ",
  },
];

/** A short list of banks for the new-payee Select. */
export const BANK_OPTIONS = [
  "みどり銀行",
  "さくら信用金庫",
  "ぐんじょう銀行",
  "あおぞら銀行",
  "ひので信託銀行",
];

/** Flat 振込手数料 used for the demo. */
export const TRANSFER_FEE = 220;

// ---------- format / mask helpers (HAND-ROLLED — see findings) ----------

/** `1234567` -> `1,234,567`. Digits only; non-digits dropped. */
export function formatYen(raw: string | number): string {
  const digits = String(raw).replace(/[^\d]/g, "");
  if (digits === "") return "";
  // Strip a leading run of zeros but keep a single 0.
  const normalized = String(parseInt(digits, 10));
  return normalized.replace(/\B(?=(\d{3})+(?!\d))/g, ",");
}

/** `"1,234,567"` / `"¥1,234,567"` -> `1234567` (number). Empty -> 0. */
export function parseYen(value: string): number {
  const digits = value.replace(/[^\d]/g, "");
  return digits === "" ? 0 : parseInt(digits, 10);
}

/** Render a yen amount with ¥ prefix + grouping, e.g. `¥1,234,567`. */
export function yen(amount: number): string {
  return `¥${amount.toLocaleString("ja-JP")}`;
}

/** Mask all but the last `keep` digits: `1234567` -> `****567`. */
export function maskTail(value: string, keep = 4): string {
  if (value.length <= keep) return value;
  const tail = value.slice(-keep);
  return `${"*".repeat(value.length - keep)}${tail}`;
}

/** `普通 ****1234` style label for an account. */
export function maskedAccountLabel(kind: AccountKind, number: string, keep = 4): string {
  return `${kind} ${maskTail(number, keep)}`;
}

export const KATAKANA_RE = /^[ァ-ヶー　\s（）()．.\-／／]+$/;

"use client";

import * as React from "react";
import {
  Alert,
  AlertDescription,
  AlertTitle,
  Badge,
  Button,
  Card,
  CardContent,
  CardHeader,
  CardTitle,
  DatePicker,
  Form,
  FormControl,
  FormDescription,
  FormField,
  FormLabel,
  FormMessage,
  Input,
  PasswordInput,
  RadioGroup,
  RadioGroupItem,
  Select,
  Separator,
  Spinner,
  StatusScreen,
  Stepper,
  Textarea,
  type StepperStep,
} from "@gunjo/ui";
import {
  BANK_OPTIONS,
  KATAKANA_RE,
  SAVED_PAYEES,
  SOURCE_ACCOUNTS,
  TRANSFER_FEE,
  formatYen,
  maskTail,
  maskedAccountLabel,
  parseYen,
  yen,
  type AccountKind,
  type Payee,
  type SourceAccount,
} from "./data";

// ---------------------------------------------------------------------------
// Wizard scaffolding. @gunjo/ui's Stepper is presentational only (no current
// index / onStepChange / focus mgmt) — the coordinator below is hand-rolled.
// ---------------------------------------------------------------------------

const STEP_LABELS = [
  "振込元口座",
  "振込先",
  "金額・詳細",
  "確認",
  "本人確認",
  "結果",
] as const;

type StepIndex = 0 | 1 | 2 | 3 | 4 | 5;

interface RecipientDraft {
  mode: "saved" | "new";
  savedId: string;
  bankName: string;
  branchName: string;
  kind: AccountKind;
  number: string;
  holder: string;
}

interface AmountDraft {
  /** Raw digits string (no separators), e.g. "1000000". */
  amount: string;
  date?: Date;
  requester: string;
  memo: string;
}

type Errors = Record<string, string | undefined>;

const DEMO_PIN = "1234"; // demo-only confirm password / 確認パスワード

export default function TransferFlow() {
  const [step, setStep] = React.useState<StepIndex>(0);

  // step 1
  const [sourceId, setSourceId] = React.useState<string>(SOURCE_ACCOUNTS[0].id);
  // step 2
  const [recipient, setRecipient] = React.useState<RecipientDraft>({
    mode: "saved",
    savedId: SAVED_PAYEES[0].id,
    bankName: "",
    branchName: "",
    kind: "普通",
    number: "",
    holder: "",
  });
  // step 3
  const [amountDraft, setAmountDraft] = React.useState<AmountDraft>({
    amount: "",
    date: undefined,
    requester: "",
    memo: "",
  });
  // step 5
  const [pin, setPin] = React.useState("");

  // result
  const [result, setResult] = React.useState<
    | { status: "idle" }
    | { status: "processing" }
    | { status: "success"; receiptId: string; at: Date }
    | { status: "declined"; reason: string }
  >({ status: "idle" });

  const [errors, setErrors] = React.useState<Errors>({});

  // --- focus management + screen-reader step announcement ---
  const headingRef = React.useRef<HTMLHeadingElement>(null);
  const [announce, setAnnounce] = React.useState("");
  const firstRender = React.useRef(true);
  React.useEffect(() => {
    if (firstRender.current) {
      firstRender.current = false;
      return;
    }
    // Move focus to the step heading and announce the change.
    headingRef.current?.focus();
    setAnnounce(
      `ステップ ${step + 1} / ${STEP_LABELS.length}：${STEP_LABELS[step]}`,
    );
  }, [step]);

  // --- derived ---
  const source = SOURCE_ACCOUNTS.find((a) => a.id === sourceId)!;
  const resolvedPayee = resolveRecipient(recipient);
  const amount = parseYen(amountDraft.amount);
  const total = amount > 0 ? amount + TRANSFER_FEE : 0;

  const stepperSteps: StepperStep[] = STEP_LABELS.map((label, i) => ({
    label,
    state: i < step ? "completed" : i === step ? "current" : "upcoming",
  }));

  // --- validators (financial correctness lives here) ---
  function validateRecipient(): boolean {
    const e: Errors = {};
    if (recipient.mode === "saved") {
      if (!recipient.savedId) e.savedId = "振込先を選択してください。";
    } else {
      if (!recipient.bankName) e.bankName = "銀行名を選択してください。";
      if (!recipient.branchName.trim())
        e.branchName = "支店名を入力してください。";
      if (!/^\d{7}$/.test(recipient.number))
        e.number = "口座番号は数字7桁で入力してください。";
      if (!recipient.holder.trim()) {
        e.holder = "口座名義を入力してください。";
      } else if (!KATAKANA_RE.test(recipient.holder.trim())) {
        e.holder = "口座名義は全角カタカナで入力してください。";
      }
    }
    setErrors(e);
    return Object.keys(e).length === 0;
  }

  function validateAmount(): boolean {
    const e: Errors = {};
    if (amount <= 0) {
      e.amount = "振込金額を入力してください。";
    } else if (total > source.balance) {
      e.amount = `残高が不足しています。振込金額と手数料の合計（${yen(
        total,
      )}）が残高（${yen(source.balance)}）を超えています。`;
    }
    setErrors(e);
    return Object.keys(e).length === 0;
  }

  function validatePin(): boolean {
    const e: Errors = {};
    if (!/^\d{4}$/.test(pin)) {
      e.pin = "確認パスワードは数字4桁で入力してください。";
    }
    setErrors(e);
    return Object.keys(e).length === 0;
  }

  // --- navigation ---
  function next() {
    if (step === 1 && !validateRecipient()) return;
    if (step === 2 && !validateAmount()) return;
    setErrors({});
    setStep((s) => Math.min(s + 1, 5) as StepIndex);
  }
  function back() {
    setErrors({});
    setStep((s) => Math.max(s - 1, 0) as StepIndex);
  }

  async function submitTransfer() {
    if (!validatePin()) return;
    setStep(5);
    setResult({ status: "processing" });
    // Simulated commit. Wrong PIN -> declined, else success.
    await new Promise((r) => setTimeout(r, 1400));
    if (pin !== DEMO_PIN) {
      setResult({
        status: "declined",
        reason:
          "確認パスワードが正しくありません。お手数ですが、もう一度お試しください。",
      });
      return;
    }
    setResult({
      status: "success",
      receiptId: `TRF-${Date.now().toString(36).toUpperCase()}`,
      at: new Date(),
    });
  }

  function retryFromAuth() {
    setPin("");
    setErrors({});
    setResult({ status: "idle" });
    setStep(4);
  }

  return (
    <main className="mx-auto flex w-full max-w-2xl flex-1 flex-col gap-6 px-4 py-8 sm:py-12">
      {/* live region for step-change announcements */}
      <div aria-live="polite" className="sr-only">
        {announce}
      </div>

      <header className="flex flex-col gap-2">
        <p className="text-sm text-muted-foreground">ぐんじょう銀行</p>
        <h1 className="text-2xl font-semibold tracking-tight">振込</h1>
      </header>

      <Stepper
        steps={stepperSteps}
        aria-label="振込の手順"
        className="w-full justify-between !p-0"
      />

      <Card>
        {step === 0 && (
          <SourceStep
            headingRef={headingRef}
            sourceId={sourceId}
            onSelect={setSourceId}
            onNext={next}
          />
        )}
        {step === 1 && (
          <RecipientStep
            headingRef={headingRef}
            recipient={recipient}
            setRecipient={setRecipient}
            errors={errors}
            onBack={back}
            onNext={next}
          />
        )}
        {step === 2 && (
          <AmountStep
            headingRef={headingRef}
            source={source}
            amountDraft={amountDraft}
            setAmountDraft={setAmountDraft}
            amount={amount}
            total={total}
            errors={errors}
            onBack={back}
            onNext={next}
          />
        )}
        {step === 3 && (
          <ReviewStep
            headingRef={headingRef}
            source={source}
            payee={resolvedPayee}
            amount={amount}
            total={total}
            date={amountDraft.date}
            requester={amountDraft.requester}
            memo={amountDraft.memo}
            onBack={back}
            onNext={next}
          />
        )}
        {step === 4 && (
          <AuthStep
            headingRef={headingRef}
            pin={pin}
            setPin={setPin}
            error={errors.pin}
            total={total}
            onBack={back}
            onSubmit={submitTransfer}
          />
        )}
        {step === 5 && (
          <ResultStep
            headingRef={headingRef}
            result={result}
            source={source}
            payee={resolvedPayee}
            total={total}
            onRetry={retryFromAuth}
          />
        )}
      </Card>
    </main>
  );
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

interface ResolvedPayee {
  bankName: string;
  branchName: string;
  kind: AccountKind;
  number: string;
  holder: string;
}

function resolveRecipient(r: RecipientDraft): ResolvedPayee {
  if (r.mode === "saved") {
    const p = SAVED_PAYEES.find((x) => x.id === r.savedId) ?? SAVED_PAYEES[0];
    return {
      bankName: p.bankName,
      branchName: p.branchName,
      kind: p.kind,
      number: p.number,
      holder: p.holder,
    };
  }
  return {
    bankName: r.bankName,
    branchName: r.branchName,
    kind: r.kind,
    number: r.number,
    holder: r.holder,
  };
}

/** Section heading wired as the focus target on step change. */
function StepHeading({
  headingRef,
  children,
}: {
  headingRef: React.RefObject<HTMLHeadingElement | null>;
  children: React.ReactNode;
}) {
  return (
    <CardTitle
      as="h2"
      ref={headingRef}
      tabIndex={-1}
      className="text-lg outline-none"
    >
      {children}
    </CardTitle>
  );
}

function FooterNav({ children }: { children: React.ReactNode }) {
  return (
    <div className="mt-2 flex flex-col-reverse gap-3 sm:flex-row sm:justify-end">
      {children}
    </div>
  );
}

// ---------------------------------------------------------------------------
// Step 1 — 振込元口座
// ---------------------------------------------------------------------------

function SourceStep({
  headingRef,
  sourceId,
  onSelect,
  onNext,
}: {
  headingRef: React.RefObject<HTMLHeadingElement | null>;
  sourceId: string;
  onSelect: (id: string) => void;
  onNext: () => void;
}) {
  return (
    <>
      <CardHeader>
        <StepHeading headingRef={headingRef}>振込元口座の選択</StepHeading>
        <p className="text-sm text-muted-foreground">
          振込に使用する口座を選んでください。
        </p>
      </CardHeader>
      <CardContent className="flex flex-col gap-4">
        <RadioGroup
          value={sourceId}
          onValueChange={onSelect}
          name="source-account"
          aria-label="振込元口座"
          className="flex flex-col gap-3"
        >
          {SOURCE_ACCOUNTS.map((acc) => {
            const selected = acc.id === sourceId;
            return (
              <label
                key={acc.id}
                className={`flex cursor-pointer items-start gap-3 rounded-lg border p-4 transition-colors ${
                  selected
                    ? "border-foreground bg-muted/50"
                    : "border-input hover:bg-muted/30"
                }`}
              >
                <RadioGroupItem value={acc.id} className="mt-1" />
                <span className="flex flex-1 flex-col gap-1">
                  <span className="flex items-center justify-between gap-2">
                    <span className="text-sm font-medium">
                      {acc.bankName} {acc.branchName}
                    </span>
                    <Badge variant="secondary">{acc.kind}</Badge>
                  </span>
                  <span className="font-mono text-sm text-muted-foreground">
                    {maskedAccountLabel(acc.kind, acc.number)}
                  </span>
                  <span className="mt-1 flex items-baseline justify-between">
                    <span className="text-xs text-muted-foreground">残高</span>
                    <span className="text-base font-semibold tabular-nums">
                      {yen(acc.balance)}
                    </span>
                  </span>
                </span>
              </label>
            );
          })}
        </RadioGroup>
      </CardContent>
      <div className="p-6 pt-0">
        <FooterNav>
          <Button className="w-full sm:w-auto" onClick={onNext}>
            次へ
          </Button>
        </FooterNav>
      </div>
    </>
  );
}

// ---------------------------------------------------------------------------
// Step 2 — 振込先
// ---------------------------------------------------------------------------

function RecipientStep({
  headingRef,
  recipient,
  setRecipient,
  errors,
  onBack,
  onNext,
}: {
  headingRef: React.RefObject<HTMLHeadingElement | null>;
  recipient: RecipientDraft;
  setRecipient: React.Dispatch<React.SetStateAction<RecipientDraft>>;
  errors: Errors;
  onBack: () => void;
  onNext: () => void;
}) {
  const set = <K extends keyof RecipientDraft>(k: K, v: RecipientDraft[K]) =>
    setRecipient((r) => ({ ...r, [k]: v }));

  return (
    <>
      <CardHeader>
        <StepHeading headingRef={headingRef}>振込先</StepHeading>
        <p className="text-sm text-muted-foreground">
          登録済みの振込先を選ぶか、新しい振込先を入力してください。
        </p>
      </CardHeader>
      <CardContent>
        <Form
          onSubmit={(e) => {
            e.preventDefault();
            onNext();
          }}
        >
          <fieldset className="flex flex-col gap-3">
            <legend className="mb-1 text-sm font-medium">振込先の指定方法</legend>
            <RadioGroup
              value={recipient.mode}
              onValueChange={(v) => set("mode", v as RecipientDraft["mode"])}
              name="recipient-mode"
              className="flex flex-col gap-2 sm:flex-row sm:gap-6"
            >
              <RadioGroupItem value="saved" label="登録済みの振込先" />
              <RadioGroupItem value="new" label="新しい振込先" />
            </RadioGroup>
          </fieldset>

          {recipient.mode === "saved" ? (
            <FormField className="p-0" error={errors.savedId}>
              <FormLabel>登録済みの振込先</FormLabel>
              <FormControl>
                <Select
                  value={recipient.savedId}
                  onChange={(e) => set("savedId", e.target.value)}
                >
                  {SAVED_PAYEES.map((p) => (
                    <option key={p.id} value={p.id}>
                      {p.label} — {p.bankName} {p.branchName}{" "}
                      {maskedAccountLabel(p.kind, p.number)}
                    </option>
                  ))}
                </Select>
              </FormControl>
              <FormMessage />
            </FormField>
          ) : (
            <>
              <FormField className="p-0" required error={errors.bankName}>
                <FormLabel>銀行名</FormLabel>
                <FormControl>
                  <Select
                    value={recipient.bankName}
                    onChange={(e) => set("bankName", e.target.value)}
                  >
                    <option value="">選択してください</option>
                    {BANK_OPTIONS.map((b) => (
                      <option key={b} value={b}>
                        {b}
                      </option>
                    ))}
                  </Select>
                </FormControl>
                <FormMessage />
              </FormField>

              <FormField className="p-0" required error={errors.branchName}>
                <FormLabel>支店名</FormLabel>
                <FormControl>
                  <Input
                    value={recipient.branchName}
                    onChange={(e) => set("branchName", e.target.value)}
                    placeholder="例：新宿支店"
                    autoComplete="off"
                  />
                </FormControl>
                <FormMessage />
              </FormField>

              <FormField className="p-0" required>
                <FormLabel>口座種別</FormLabel>
                <FormControl>
                  <Select
                    value={recipient.kind}
                    onChange={(e) =>
                      set("kind", e.target.value as AccountKind)
                    }
                  >
                    <option value="普通">普通</option>
                    <option value="当座">当座</option>
                  </Select>
                </FormControl>
              </FormField>

              <FormField className="p-0" required error={errors.number}>
                <FormLabel>口座番号</FormLabel>
                <FormControl>
                  <Input
                    value={recipient.number}
                    onChange={(e) =>
                      set("number", e.target.value.replace(/\D/g, "").slice(0, 7))
                    }
                    inputMode="numeric"
                    placeholder="7桁の数字"
                    autoComplete="off"
                  />
                </FormControl>
                <FormDescription>半角数字7桁で入力してください。</FormDescription>
                <FormMessage />
              </FormField>

              <FormField className="p-0" required error={errors.holder}>
                <FormLabel>口座名義</FormLabel>
                <FormControl>
                  <Input
                    value={recipient.holder}
                    onChange={(e) => set("holder", e.target.value)}
                    placeholder="例：ヤマダ タロウ"
                    autoComplete="off"
                  />
                </FormControl>
                <FormDescription>全角カタカナで入力してください。</FormDescription>
                <FormMessage />
              </FormField>
            </>
          )}

          <FooterNav>
            <Button
              type="button"
              variant="outline"
              className="w-full sm:w-auto"
              onClick={onBack}
            >
              戻る
            </Button>
            <Button type="submit" className="w-full sm:w-auto">
              次へ
            </Button>
          </FooterNav>
        </Form>
      </CardContent>
    </>
  );
}

// ---------------------------------------------------------------------------
// Step 3 — 金額・詳細
// ---------------------------------------------------------------------------

function AmountStep({
  headingRef,
  source,
  amountDraft,
  setAmountDraft,
  amount,
  total,
  errors,
  onBack,
  onNext,
}: {
  headingRef: React.RefObject<HTMLHeadingElement | null>;
  source: SourceAccount;
  amountDraft: AmountDraft;
  setAmountDraft: React.Dispatch<React.SetStateAction<AmountDraft>>;
  amount: number;
  total: number;
  errors: Errors;
  onBack: () => void;
  onNext: () => void;
}) {
  const set = <K extends keyof AmountDraft>(k: K, v: AmountDraft[K]) =>
    setAmountDraft((d) => ({ ...d, [k]: v }));

  const insufficient = amount > 0 && total > source.balance;

  return (
    <>
      <CardHeader>
        <StepHeading headingRef={headingRef}>金額・詳細</StepHeading>
        <p className="text-sm text-muted-foreground">
          振込元残高：
          <span className="font-medium tabular-nums text-foreground">
            {yen(source.balance)}
          </span>
        </p>
      </CardHeader>
      <CardContent>
        <Form
          onSubmit={(e) => {
            e.preventDefault();
            onNext();
          }}
        >
          {/* Amount — hand-rolled currency field (no DS money input). */}
          <FormField className="p-0" required error={errors.amount}>
            <FormLabel>振込金額</FormLabel>
            <FormControl>
              <div className="relative">
                <span
                  aria-hidden="true"
                  className="pointer-events-none absolute left-3 top-1/2 -translate-y-1/2 text-sm text-muted-foreground"
                >
                  ¥
                </span>
                <Input
                  value={formatYen(amountDraft.amount)}
                  onChange={(e) => set("amount", String(parseYen(e.target.value)))}
                  inputMode="numeric"
                  placeholder="0"
                  autoComplete="off"
                  className="pl-7 text-right text-base font-semibold tabular-nums"
                />
              </div>
            </FormControl>
            <FormDescription>半角数字で入力してください（円）。</FormDescription>
            <FormMessage />
          </FormField>

          {/* Fee + total summary */}
          <div className="rounded-lg border bg-muted/30 p-4 text-sm">
            <dl className="flex flex-col gap-2">
              <div className="flex items-center justify-between">
                <dt className="text-muted-foreground">振込金額</dt>
                <dd className="tabular-nums">{yen(amount)}</dd>
              </div>
              <div className="flex items-center justify-between">
                <dt className="text-muted-foreground">振込手数料</dt>
                <dd className="tabular-nums">{yen(TRANSFER_FEE)}</dd>
              </div>
              <Separator className="my-1" />
              <div className="flex items-center justify-between font-semibold">
                <dt>合計お引落し額</dt>
                <dd className="tabular-nums">{yen(total)}</dd>
              </div>
            </dl>
          </div>

          {insufficient && (
            <Alert variant="destructive">
              <AlertTitle as="p">残高不足</AlertTitle>
              <AlertDescription>
                合計お引落し額（{yen(total)}）が振込元残高（
                {yen(source.balance)}）を超えています。
              </AlertDescription>
            </Alert>
          )}

          <FormField className="p-0">
            <FormLabel>振込指定日（任意）</FormLabel>
            <FormControl>
              <DatePicker
                value={amountDraft.date}
                onValueChange={(d) => set("date", d)}
                locale={undefined}
                placeholder="今すぐ振込む場合は空欄"
              />
            </FormControl>
            <FormDescription>
              指定がない場合は当日扱いで処理されます。
            </FormDescription>
          </FormField>

          <FormField className="p-0">
            <FormLabel>依頼人名（任意）</FormLabel>
            <FormControl>
              <Input
                value={amountDraft.requester}
                onChange={(e) => set("requester", e.target.value)}
                placeholder="空欄の場合は口座名義を使用"
                autoComplete="off"
              />
            </FormControl>
          </FormField>

          <FormField className="p-0">
            <FormLabel>メモ（任意）</FormLabel>
            <FormControl>
              <Textarea
                value={amountDraft.memo}
                onChange={(e) => set("memo", e.target.value)}
                rows={2}
                placeholder="ご自身用のメモ"
              />
            </FormControl>
          </FormField>

          <FooterNav>
            <Button
              type="button"
              variant="outline"
              className="w-full sm:w-auto"
              onClick={onBack}
            >
              戻る
            </Button>
            <Button type="submit" className="w-full sm:w-auto">
              確認へ進む
            </Button>
          </FooterNav>
        </Form>
      </CardContent>
    </>
  );
}

// ---------------------------------------------------------------------------
// Step 4 — 確認
// ---------------------------------------------------------------------------

function Row({
  label,
  children,
  emphasize,
}: {
  label: string;
  children: React.ReactNode;
  emphasize?: boolean;
}) {
  return (
    <div className="flex items-start justify-between gap-4 py-2.5">
      <dt className="text-sm text-muted-foreground">{label}</dt>
      <dd
        className={`text-right text-sm ${
          emphasize ? "text-base font-semibold tabular-nums" : "font-medium"
        }`}
      >
        {children}
      </dd>
    </div>
  );
}

function ReviewStep({
  headingRef,
  source,
  payee,
  amount,
  total,
  date,
  requester,
  memo,
  onBack,
  onNext,
}: {
  headingRef: React.RefObject<HTMLHeadingElement | null>;
  source: SourceAccount;
  payee: ResolvedPayee;
  amount: number;
  total: number;
  date?: Date;
  requester: string;
  memo: string;
  onBack: () => void;
  onNext: () => void;
}) {
  return (
    <>
      <CardHeader>
        <StepHeading headingRef={headingRef}>振込内容の確認</StepHeading>
        <p className="text-sm text-muted-foreground">
          以下の内容で振込みます。よろしければ「この内容で振込む」を押してください。
        </p>
      </CardHeader>
      <CardContent className="flex flex-col gap-4">
        <section aria-labelledby="rv-from">
          <h3
            id="rv-from"
            className="mb-1 text-xs font-semibold uppercase tracking-wide text-muted-foreground"
          >
            振込元
          </h3>
          <dl className="divide-y">
            <Row label="口座">
              {source.bankName} {source.branchName}
            </Row>
            <Row label="口座番号">
              <span className="font-mono">
                {source.kind} {maskTail(source.number)}
              </span>
            </Row>
          </dl>
        </section>

        <Separator />

        <section aria-labelledby="rv-to">
          <h3
            id="rv-to"
            className="mb-1 text-xs font-semibold uppercase tracking-wide text-muted-foreground"
          >
            振込先
          </h3>
          <dl className="divide-y">
            <Row label="銀行・支店">
              {payee.bankName} {payee.branchName}
            </Row>
            <Row label="口座番号">
              <span className="font-mono">
                {payee.kind} {maskTail(payee.number)}
              </span>
            </Row>
            <Row label="口座名義">{payee.holder}</Row>
          </dl>
        </section>

        <Separator />

        <section aria-labelledby="rv-amount">
          <h3
            id="rv-amount"
            className="mb-1 text-xs font-semibold uppercase tracking-wide text-muted-foreground"
          >
            金額
          </h3>
          <dl className="divide-y">
            <Row label="振込金額">{yen(amount)}</Row>
            <Row label="振込手数料">{yen(TRANSFER_FEE)}</Row>
            <Row label="合計お引落し額" emphasize>
              {yen(total)}
            </Row>
            <Row label="振込指定日">
              {date
                ? date.toLocaleDateString("ja-JP", {
                    year: "numeric",
                    month: "long",
                    day: "numeric",
                  })
                : "本日（当日扱い）"}
            </Row>
            {requester && <Row label="依頼人名">{requester}</Row>}
            {memo && <Row label="メモ">{memo}</Row>}
