// ---------------------------------------------------------------------------
// Step 5 — 本人確認
// ---------------------------------------------------------------------------

function AuthStep({
  headingRef,
  pin,
  setPin,
  error,
  total,
  onBack,
  onSubmit,
}: {
  headingRef: React.RefObject<HTMLHeadingElement | null>;
  pin: string;
  setPin: (v: string) => void;
  error?: string;
  total: number;
  onBack: () => void;
  onSubmit: () => void;
}) {
  return (
    <>
      <CardHeader>
        <StepHeading headingRef={headingRef}>本人確認</StepHeading>
        <p className="text-sm text-muted-foreground">
          {yen(total)} を振込みます。確認パスワード（数字4桁）を入力してください。
        </p>
      </CardHeader>
      <CardContent>
        <Form
          onSubmit={(e) => {
            e.preventDefault();
            onSubmit();
          }}
        >
          <FormField className="p-0" required error={error}>
            <FormLabel>確認パスワード</FormLabel>
            <FormControl>
              <PasswordInput
                value={pin}
                onChange={(e) =>
                  setPin(e.target.value.replace(/\D/g, "").slice(0, 4))
                }
                inputMode="numeric"
                autoComplete="one-time-code"
                placeholder="••••"
                showLabel="確認パスワードを表示"
                hideLabel="確認パスワードを隠す"
              />
            </FormControl>
            <FormDescription>デモ用パスワードは 1234 です。</FormDescription>
            <FormMessage />
          </FormField>

          <Alert variant="info">
            <AlertTitle as="p">セキュリティのご案内</AlertTitle>
            <AlertDescription>
              確認パスワードは第三者に知られないようご注意ください。当行から
              電話・メールでお尋ねすることはありません。
            </AlertDescription>
          </Alert>

          <FooterNav>
            <Button
              type="button"
              variant="outline"
              className="w-full sm:w-auto"
              onClick={onBack}
            >
              戻る
            </Button>
            <Button type="submit" className="w-full sm:w-auto">
              振込を実行
            </Button>
          </FooterNav>
        </Form>
      </CardContent>
    </>
  );
}

// ---------------------------------------------------------------------------
// Step 6 — 結果
// ---------------------------------------------------------------------------

function ResultStep({
  headingRef,
  result,
  source,
  payee,
  total,
  onRetry,
}: {
  headingRef: React.RefObject<HTMLHeadingElement | null>;
  result:
    | { status: "idle" }
    | { status: "processing" }
    | { status: "success"; receiptId: string; at: Date }
    | { status: "declined"; reason: string };
  source: SourceAccount;
  payee: ResolvedPayee;
  total: number;
  onRetry: () => void;
}) {
  if (result.status === "processing" || result.status === "idle") {
    return (
      <CardContent className="py-12">
        <div
          role="status"
          aria-live="polite"
          className="flex flex-col items-center gap-4 text-center"
        >
          <Spinner size="lg" />
          <h2
            ref={headingRef}
            tabIndex={-1}
            className="text-lg font-semibold outline-none"
          >
            振込を処理しています…
          </h2>
          <p className="text-sm text-muted-foreground">
            画面を閉じずにお待ちください。
          </p>
        </div>
      </CardContent>
    );
  }

  if (result.status === "declined") {
    return (
      <CardContent>
        <StatusScreen
          variant="error"
          code={undefined}
          icon={<DeclinedIcon />}
          headingLevel={2}
          title="振込を完了できませんでした"
          description={result.reason}
          action={
            <Button onClick={onRetry}>もう一度入力する</Button>
          }
        />
        {/* StatusScreen title isn't focusable; mirror focus target for SR. */}
        <span
          ref={headingRef}
          tabIndex={-1}
          className="sr-only"
          role="status"
        >
          振込を完了できませんでした。{result.reason}
        </span>
      </CardContent>
    );
  }

  // success
  return (
    <CardContent>
      <StatusScreen
        code={undefined}
        icon={<SuccessIcon />}
        headingLevel={2}
        title="振込を受け付けました"
        description={`${payee.holder} 様へ ${yen(total)} の振込手続きが完了しました。`}
        details={[
          `受付番号: ${result.receiptId}`,
          `受付日時: ${result.at.toLocaleString("ja-JP")}`,
          `振込元: ${source.bankName} ${source.branchName} ${source.kind} ${maskTail(
            source.number,
          )}`,
          `振込先: ${payee.bankName} ${payee.branchName} ${payee.kind} ${maskTail(
            payee.number,
          )}`,
        ].join("\n")}
        action={
          <Button variant="outline" asChild>
            <a href="/transfer">続けて振込む</a>
          </Button>
        }
      />
      <span ref={headingRef} tabIndex={-1} className="sr-only" role="status">
        振込を受け付けました。受付番号 {result.receiptId}。
      </span>
    </CardContent>
  );
}

function SuccessIcon() {
  return (
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2} className="text-success">
      <path d="M20 6 9 17l-5-5" strokeLinecap="round" strokeLinejoin="round" />
    </svg>
  );
}

function DeclinedIcon() {
  return (
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2}>
      <circle cx="12" cy="12" r="10" />
      <path d="m15 9-6 6M9 9l6 6" strokeLinecap="round" strokeLinejoin="round" />
    </svg>
  );
}
